from aiocoap import Context, Message, Code, get_endpoints
import asyncio

async def main():
    server = await Context.create_server()
    
    @server.resource('sensors/temp')
    class TemperatureResource:
        async def render_get(self, request):
            temp = "25.0°C"  # Simulated temperature reading
            return Message(code=Code.Content, payload=temp.encode())
        
        async def render_put(self, request):
            new_temp = request.payload.decode()
            print(f"Setting new temperature: {new_temp}")
            return Message(code=Code.Changed)
    
    @server.resource('actuators/light')
    class LightResource:
        async def render_get(self, request):
            light_state = "On"  # Simulated light state
            return Message(code=Code.Content, payload=light_state.encode())
        
        async def render_put(self, request):
            new_state = request.payload.decode()
            print(f"Setting new light state: {new_state}")
            return Message(code=Code.Changed)
    
    print("CoAP server started")
    await asyncio.Future()  # Run forever

if __name__ == "__main__":
    asyncio.run(main())